function formatText(input) {
  // const formatted = input
  //   .replace(/\*\*\*(.*?)\*\*\*/g, '$1')
  //   .replace(/\*\*(.*?)\*\*/g, '$1')
  //   .replace(/\*(.*?)\*/g, '$1')
  //   .replace(/\n/g, '<br>')
  //   .replace(/"/g, '&quot;');

  // Convert to JSON string
  let jsonString = JSON.stringify(input);
  // Remove surrounding quotes only if they exist
  if (jsonString.startsWith('"') && jsonString.endsWith('"')) {
    jsonString = jsonString.slice(1, -1);
  }
  return jsonString;
}

let image_prompt = formatText($("Pain Point - Text-To-Image").item.json.output);
let video_prompt = formatText($("Pain Point - Image-To-Video").item.json.output);

return {
  json: {
    image_prompt,
    video_prompt
  }
}

